import Fastify from 'fastify'
import cors from '@fastify/cors'
import jwt from '@fastify/jwt'
import multipart from '@fastify/multipart'
import rateLimit from '@fastify/rate-limit'
import { config } from './config/index.js'
import prismaPlugin from './plugins/prisma.js'
import authRoutes from './routes/auth.js'
import articleRoutes from './routes/articles.js'
import commentRoutes from './routes/comments.js'
import newsletterRoutes from './routes/newsletter.js'
import roomRoutes from './routes/rooms.js'
import uploadRoutes from './routes/upload.js'
import userRoutes from './routes/users.js'

export async function buildApp() {
  const app = Fastify({
    logger: {
      level: config.NODE_ENV === 'production' ? 'warn' : 'info',
    },
  })

  // Plugins
  await app.register(cors, {
    origin: config.FRONTEND_URL,
    credentials: true,
  })

  await app.register(jwt, {
    secret: config.JWT_SECRET,
    sign: { expiresIn: '15m' },
  })

  await app.register(multipart, {
    limits: { fileSize: 500 * 1024 * 1024 }, // 500MB
  })

  await app.register(rateLimit, {
    max: 100,
    timeWindow: '1 minute',
  })

  // Prisma
  await app.register(prismaPlugin)

  // Health check
  app.get('/health', async () => ({ status: 'ok', timestamp: new Date().toISOString() }))

  // Routes
  await app.register(authRoutes, { prefix: '/api/auth' })
  await app.register(articleRoutes, { prefix: '/api/articles' })
  await app.register(commentRoutes, { prefix: '/api' })
  await app.register(newsletterRoutes, { prefix: '/api/newsletter' })
  await app.register(roomRoutes, { prefix: '/api/rooms' })
  await app.register(uploadRoutes, { prefix: '/api/upload' })
  await app.register(userRoutes, { prefix: '/api/users' })

  return app
}

import { FastifyRequest, FastifyReply } from 'fastify'

export async function authenticate(
  request: FastifyRequest,
  reply: FastifyReply
) {
  try {
    await request.jwtVerify()
  } catch (err) {
    reply.status(401).send({ error: 'Unauthorized' })
  }
}

export async function optionalAuth(
  request: FastifyRequest,
  reply: FastifyReply
) {
  try {
    await request.jwtVerify()
  } catch {
    // Ignore - allow anonymous access
  }
}

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate, optionalAuth } from '../middleware/auth.js'

const commentSchema = z.object({
  content: z.string().min(1),
  authorName: z.string().min(1).optional(),
  parentId: z.string().uuid().optional(),
})

const commentRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Get comments for article
  fastify.get('/articles/:slug/comments', async (request, reply) => {
    const { slug } = request.params as { slug: string }

    const article = await fastify.prisma.article.findUnique({
      where: { slug },
      select: { id: true },
    })

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    const comments = await fastify.prisma.comment.findMany({
      where: { articleId: article.id, parentId: null },
      include: {
        author: { select: { id: true, name: true, avatar: true } },
        replies: {
          include: {
            author: { select: { id: true, name: true, avatar: true } },
          },
          orderBy: { createdAt: 'asc' },
        },
      },
      orderBy: { createdAt: 'desc' },
    })

    return reply.send(comments)
  })

  // Add comment
  fastify.post('/articles/:slug/comments', { preHandler: optionalAuth }, async (request, reply) => {
    const { slug } = request.params as { slug: string }
    const data = commentSchema.parse(request.body)

    const article = await fastify.prisma.article.findUnique({
      where: { slug },
      select: { id: true },
    })

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    const comment = await fastify.prisma.comment.create({
      data: {
        articleId: article.id,
        authorId: request.user?.id,
        authorName: request.user?.id
          ? (await fastify.prisma.user.findUnique({ where: { id: request.user.id }, select: { name: true } }))?.name || 'User'
          : (data.authorName || 'Anonymous'),
        content: data.content,
        parentId: data.parentId,
      },
      include: {
        author: { select: { id: true, name: true, avatar: true } },
      },
    })

    return reply.status(201).send(comment)
  })

  // Delete comment
  fastify.delete('/comments/:id', { preHandler: optionalAuth }, async (request, reply) => {
    const { id } = request.params as { id: string }

    const comment = await fastify.prisma.comment.findUnique({ where: { id } })

    if (!comment) {
      return reply.status(404).send({ error: 'Comment not found' })
    }

    // Allow deletion if user is comment author or admin
    if (comment.authorId !== request.user?.id && request.user?.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Forbidden' })
    }

    await fastify.prisma.comment.delete({ where: { id } })

    return reply.send({ message: 'Comment deleted' })
  })
}

export default commentRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'

const newsletterSchema = z.object({
  email: z.string().email(),
})

const newsletterRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Subscribe
  fastify.post('/subscribe', async (request, reply) => {
    const { email } = newsletterSchema.parse(request.body)

    const existing = await fastify.prisma.newsletter.findUnique({
      where: { email },
    })

    if (existing) {
      if (!existing.subscribed) {
        await fastify.prisma.newsletter.update({
          where: { email },
          data: { subscribed: true, subscribedAt: new Date(), unsubscribedAt: null },
        })
        return reply.send({ message: 'Re-subscribed successfully' })
      }
      return reply.status(400).send({ error: 'Already subscribed' })
    }

    await fastify.prisma.newsletter.create({
      data: { email },
    })

    return reply.status(201).send({ message: 'Subscribed successfully' })
  })

  // Unsubscribe
  fastify.post('/unsubscribe', async (request, reply) => {
    const { email } = newsletterSchema.parse(request.body)

    const existing = await fastify.prisma.newsletter.findUnique({
      where: { email },
    })

    if (!existing || !existing.subscribed) {
      return reply.status(404).send({ error: 'Not found or already unsubscribed' })
    }

    await fastify.prisma.newsletter.update({
      where: { email },
      data: { subscribed: false, unsubscribedAt: new Date() },
    })

    return reply.send({ message: 'Unsubscribed successfully' })
  })

  // Get stats (admin only)
  fastify.get('/stats', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const [total, subscribed, unsubscribed] = await Promise.all([
      fastify.prisma.newsletter.count(),
      fastify.prisma.newsletter.count({ where: { subscribed: true } }),
      fastify.prisma.newsletter.count({ where: { subscribed: false } }),
    ])

    return reply.send({ total, subscribed, unsubscribed })
  })
}

export default newsletterRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'

const roomCreateSchema = z.object({
  name: z.string().min(1),
})

function generateRoomCode(): string {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'
  let code = ''
  for (let i = 0; i < 6; i++) {
    code += chars[Math.floor(Math.random() * chars.length)]
  }
  return code
}

const roomRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Create room
  fastify.post('/create', { preHandler: authenticate }, async (request, reply) => {
    const { name } = roomCreateSchema.parse(request.body)

    let code = generateRoomCode()
    // Ensure unique
    while (await fastify.prisma.studyRoom.findUnique({ where: { code } })) {
      code = generateRoomCode()
    }

    const room = await fastify.prisma.studyRoom.create({
      data: {
        code,
        name,
        creatorId: request.user.id,
        expiresAt: new Date(Date.now() + 4 * 60 * 60 * 1000), // 4 hours
      },
      include: { creator: { select: { id: true, name: true } } },
    })

    return reply.status(201).send(room)
  })

  // Get room by code
  fastify.get('/:code', async (request, reply) => {
    const { code } = request.params as { code: string }

    const room = await fastify.prisma.studyRoom.findUnique({
      where: { code: code.toUpperCase() },
      include: { creator: { select: { id: true, name: true } } },
    })

    if (!room) {
      return reply.status(404).send({ error: 'Room not found' })
    }

    if (!room.isActive) {
      return reply.status(410).send({ error: 'Room is closed' })
    }

    return reply.send(room)
  })

  // Join room
  fastify.post('/:code/join', { preHandler: authenticate }, async (request, reply) => {
    const { code } = request.params as { code: string }

    const room = await fastify.prisma.studyRoom.findUnique({
      where: { code: code.toUpperCase() },
    })

    if (!room) {
      return reply.status(404).send({ error: 'Room not found' })
    }

    if (!room.isActive) {
      return reply.status(410).send({ error: 'Room is closed' })
    }

    return reply.send({ message: 'Joined successfully', roomCode: room.code })
  })

  // Close room
  fastify.delete('/:code', { preHandler: authenticate }, async (request, reply) => {
    const { code } = request.params as { code: string }

    const room = await fastify.prisma.studyRoom.findUnique({
      where: { code: code.toUpperCase() },
    })

    if (!room) {
      return reply.status(404).send({ error: 'Room not found' })
    }

    if (room.creatorId !== request.user.id && request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Only room creator can close' })
    }

    await fastify.prisma.studyRoom.update({
      where: { id: room.id },
      data: { isActive: false },
    })

    return reply.send({ message: 'Room closed' })
  })
}

export default roomRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'

const updateProfileSchema = z.object({
  name: z.string().min(2).optional(),
  avatar: z.string().url().optional(),
})

const userRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Get current user
  fastify.get('/me', { preHandler: authenticate }, async (request, reply) => {
    const user = await fastify.prisma.user.findUnique({
      where: { id: request.user.id },
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
        avatar: true,
        createdAt: true,
      },
    })

    if (!user) {
      return reply.status(404).send({ error: 'User not found' })
    }

    return reply.send(user)
  })

  // Update profile
  fastify.put('/me', { preHandler: authenticate }, async (request, reply) => {
    const data = updateProfileSchema.parse(request.body)

    const user = await fastify.prisma.user.update({
      where: { id: request.user.id },
      data,
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
        avatar: true,
      },
    })

    return reply.send(user)
  })

  // Get public profile
  fastify.get('/:id/public', async (request, reply) => {
    const { id } = request.params as { id: string }

    const user = await fastify.prisma.user.findUnique({
      where: { id },
      select: {
        id: true,
        name: true,
        avatar: true,
        createdAt: true,
        _count: {
          select: { articles: true },
        },
      },
    })

    if (!user) {
      return reply.status(404).send({ error: 'User not found' })
    }

    return reply.send(user)
  })
}

export default userRoutes

