import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import bcrypt from 'bcryptjs'
import { z } from 'zod'
import { User, Role } from '../models/User.js'
import { RefreshToken } from '../models/RefreshToken.js'

const registerSchema = z.object({
  email: z.string().email(),
  password: z.string().min(8),
  name: z.string().min(2),
})

const loginSchema = z.object({
  email: z.string().email(),
  password: z.string(),
})

const authRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Register
  fastify.post('/register', async (request, reply) => {
    const body = registerSchema.parse(request.body)

    const existing = await User.findOne({ email: body.email.toLowerCase() })

    if (existing) {
      return reply.status(400).send({ error: 'Email already registered' })
    }

    const passwordHash = await bcrypt.hash(body.password, 12)

    const user = await User.create({
      email: body.email.toLowerCase(),
      passwordHash,
      name: body.name,
      role: Role.USER,
    })

    const accessToken = fastify.jwt.sign({
      id: user._id.toString(),
      email: user.email,
      role: user.role,
    })

    const refreshToken = fastify.jwt.sign(
      { id: user._id.toString(), email: user.email, role: user.role },
      { expiresIn: '7d' }
    )

    await RefreshToken.create({
      token: refreshToken,
      userId: user._id,
      expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
    })

    return reply.send({
      user: { id: user._id.toString(), email: user.email, name: user.name, role: user.role },
      accessToken,
      refreshToken,
    })
  })

  // Login
  fastify.post('/login', async (request, reply) => {
    const body = loginSchema.parse(request.body)

    const user = await User.findOne({ email: body.email.toLowerCase() })

    if (!user) {
      return reply.status(401).send({ error: 'Invalid credentials' })
    }

    const valid = await bcrypt.compare(body.password, user.passwordHash)

    if (!valid) {
      return reply.status(401).send({ error: 'Invalid credentials' })
    }

    const accessToken = fastify.jwt.sign({
      id: user._id.toString(),
      email: user.email,
      role: user.role,
    })

    const refreshToken = fastify.jwt.sign(
      { id: user._id.toString(), email: user.email, role: user.role },
      { expiresIn: '7d' }
    )

    // Delete old tokens for this user before creating new ones (token rotation)
    await RefreshToken.deleteMany({ userId: user._id })

    await RefreshToken.create({
      token: refreshToken,
      userId: user._id,
      expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
    })

    return reply.send({
      user: { id: user._id.toString(), email: user.email, name: user.name, role: user.role },
      accessToken,
      refreshToken,
    })
  })

  // Refresh token
  fastify.post('/refresh', async (request, reply) => {
    const { refreshToken } = request.body as { refreshToken: string }

    try {
      const decoded = fastify.jwt.verify(refreshToken) as unknown as {
        id: string
        email: string
        role: string
      }

      const stored = await RefreshToken.findOne({ token: refreshToken }).populate('userId')

      if (!stored || stored.expiresAt < new Date()) {
        return reply.status(401).send({ error: 'Invalid refresh token' })
      }

      const accessToken = fastify.jwt.sign({
        id: decoded.id,
        email: decoded.email,
        role: decoded.role,
      })

      return reply.send({ accessToken })
    } catch {
      return reply.status(401).send({ error: 'Invalid refresh token' })
    }
  })

  // Logout
  fastify.post('/logout', async (request, reply) => {
    const { refreshToken } = request.body as { refreshToken: string }

    if (refreshToken) {
      await RefreshToken.deleteMany({ token: refreshToken })
    }

    return reply.send({ message: 'Logged out successfully' })
  })
}

export default authRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'
import { Article, Category } from '../models/Article.js'
import { User } from '../models/User.js'

const articleCreateSchema = z.object({
  slug: z.string().min(1),
  title: z.string().min(1),
  excerpt: z.string(),
  content: z.string(),
  category: z.enum(['AI', 'CTDL', 'WEB_DEV', 'DEVOPS', 'MOBILE']),
  tags: z.array(z.string()),
  coverImage: z.string().optional(),
  readingTime: z.number().optional(),
})

const articleUpdateSchema = articleCreateSchema.partial()

const articleQuerySchema = z.object({
  page: z.coerce.number().min(1).default(1),
  limit: z.coerce.number().min(1).max(100).default(10),
  category: z.string().optional(),
  tag: z.string().optional(),
  search: z.string().optional(),
})

const articleRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // List articles (public)
  fastify.get('/', async (request, reply) => {
    const query = articleQuerySchema.parse(request.query)
    const skip = (query.page - 1) * query.limit

    const filter: any = {
      published: true,
    }

    if (query.category) {
      filter.category = query.category.toUpperCase()
    }

    if (query.tag) {
      filter.tags = query.tag
    }

    if (query.search) {
      filter.$or = [
        { title: { $regex: query.search, $options: 'i' } },
        { excerpt: { $regex: query.search, $options: 'i' } },
      ]
    }

    const [articles, total] = await Promise.all([
      Article.find(filter)
        .populate('authorId', 'id name avatar')
        .sort({ publishedAt: -1 })
        .skip(skip)
        .limit(query.limit)
        .lean(),
      Article.countDocuments(filter),
    ])

    // Add comment count to each article
    const articlesWithCount = await Promise.all(
      articles.map(async (article: any) => {
        const { Comment } = await import('../models/Comment.js')
        const commentCount = await Comment.countDocuments({ articleId: article._id })
        return {
          ...article,
          _count: { comments: commentCount },
        }
      })
    )

    return reply.send({
      articles: articlesWithCount,
      pagination: {
        page: query.page,
        limit: query.limit,
        total,
        totalPages: Math.ceil(total / query.limit),
      },
    })
  })

  // Get single article by slug
  fastify.get('/:slug', async (request, reply) => {
    const { slug } = request.params as { slug: string }

    const article = await Article.findOne({ slug })
      .populate('authorId', 'id name avatar')
      .populate({
        path: 'comments',
        match: { parentId: undefined },
        populate: [
          { path: 'authorId', select: 'id name avatar' },
          {
            path: 'replies',
            populate: { path: 'authorId', select: 'id name avatar' },
            options: { sort: { createdAt: 1 } },
          },
        ],
        options: { sort: { createdAt: -1 } },
      })
      .lean()

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send(article)
  })

  // Create article (admin only)
  fastify.post('/', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const data = articleCreateSchema.parse(request.body)

    const article = await Article.create({
      ...data,
      authorId: request.user.id,
    })

    await article.populate('authorId', 'id name avatar')

    return reply.status(201).send(article)
  })

  // Update article (admin only)
  fastify.put('/:id', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }
    const data = articleUpdateSchema.parse(request.body)

    const article = await Article.findByIdAndUpdate(id, data, { new: true }).populate('authorId', 'id name avatar')

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send(article)
  })

  // Delete article (admin only)
  fastify.delete('/:id', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }

    const article = await Article.findByIdAndDelete(id)

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send({ message: 'Article deleted' })
  })

  // Publish/unpublish article (admin only)
  fastify.patch('/:id/publish', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }
    const { published } = request.body as { published: boolean }

    const article = await Article.findByIdAndUpdate(
      id,
      {
        published,
        publishedAt: published ? new Date() : null,
      },
      { new: true }
    )

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send(article)
  })
}

export default articleRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate, optionalAuth } from '../middleware/auth.js'
import { Comment } from '../models/Comment.js'
import { Article } from '../models/Article.js'
import { User } from '../models/User.js'

const commentSchema = z.object({
  content: z.string().min(1),
  authorName: z.string().min(1).optional(),
  parentId: z.string().optional(),
})

const commentRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Get comments for article
  fastify.get('/articles/:slug/comments', async (request, reply) => {
    const { slug } = request.params as { slug: string }

    const article = await Article.findOne({ slug }).select('_id')

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    const comments = await Comment.find({ articleId: article._id, parentId: undefined })
      .populate('authorId', 'id name avatar')
      .populate({
        path: 'replies',
        populate: { path: 'authorId', select: 'id name avatar' },
        options: { sort: { createdAt: 1 } },
      })
      .sort({ createdAt: -1 })
      .lean()

    return reply.send(comments)
  })

  // Add comment
  fastify.post('/articles/:slug/comments', { preHandler: optionalAuth }, async (request, reply) => {
    const { slug } = request.params as { slug: string }
    const data = commentSchema.parse(request.body)

    const article = await Article.findOne({ slug }).select('_id')

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    let authorName = 'Anonymous'
    let authorId: any = undefined

    if (request.user?.id) {
      const user = await User.findById(request.user.id).select('name')
      authorName = user?.name || 'User'
      authorId = request.user.id
    } else {
      authorName = data.authorName || 'Anonymous'
    }

    const comment = await Comment.create({
      articleId: article._id,
      authorId,
      authorName,
      content: data.content,
      parentId: data.parentId || undefined,
    })

    await comment.populate('authorId', 'id name avatar')

    return reply.status(201).send(comment)
  })

  // Delete comment
  fastify.delete('/comments/:id', { preHandler: optionalAuth }, async (request, reply) => {
    const { id } = request.params as { id: string }

    const comment = await Comment.findById(id)

    if (!comment) {
      return reply.status(404).send({ error: 'Comment not found' })
    }

    // Allow deletion if user is comment author or admin
    if (comment.authorId?.toString() !== request.user?.id && request.user?.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Forbidden' })
    }

    await Comment.findByIdAndDelete(id)

    return reply.send({ message: 'Comment deleted' })
  })
}

export default commentRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'
import { Newsletter } from '../models/Newsletter.js'

const newsletterSchema = z.object({
  email: z.string().email(),
})

const newsletterRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Subscribe
  fastify.post('/subscribe', async (request, reply) => {
    const { email } = newsletterSchema.parse(request.body)

    const existing = await Newsletter.findOne({ email: email.toLowerCase() })

    if (existing) {
      if (!existing.subscribed) {
        existing.subscribed = true
        existing.subscribedAt = new Date()
        existing.unsubscribedAt = undefined
        await existing.save()
        return reply.send({ message: 'Re-subscribed successfully' })
      }
      return reply.status(400).send({ error: 'Already subscribed' })
    }

    await Newsletter.create({ email: email.toLowerCase() })

    return reply.status(201).send({ message: 'Subscribed successfully' })
  })

  // Unsubscribe
  fastify.post('/unsubscribe', async (request, reply) => {
    const { email } = newsletterSchema.parse(request.body)

    const existing = await Newsletter.findOne({ email: email.toLowerCase() })

    if (!existing || !existing.subscribed) {
      return reply.status(404).send({ error: 'Not found or already unsubscribed' })
    }

    existing.subscribed = false
    existing.unsubscribedAt = new Date()
    await existing.save()

    return reply.send({ message: 'Unsubscribed successfully' })
  })

  // Get stats (admin only)
  fastify.get('/stats', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const [total, subscribed, unsubscribed] = await Promise.all([
      Newsletter.countDocuments(),
      Newsletter.countDocuments({ subscribed: true }),
      Newsletter.countDocuments({ subscribed: false }),
    ])

    return reply.send({ total, subscribed, unsubscribed })
  })
}

export default newsletterRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'
import { User } from '../models/User.js'
import { Article } from '../models/Article.js'

const updateProfileSchema = z.object({
  name: z.string().min(2).optional(),
  avatar: z.string().url().optional(),
})

const userRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Get current user
  fastify.get('/me', { preHandler: authenticate }, async (request, reply) => {
    const user = await User.findById(request.user.id).select('email name role avatar createdAt')

    if (!user) {
      return reply.status(404).send({ error: 'User not found' })
    }

    return reply.send({
      id: user._id.toString(),
      email: user.email,
      name: user.name,
      role: user.role,
      avatar: user.avatar,
      createdAt: (user as any).createdAt,
    })
  })

  // Update profile
  fastify.put('/me', { preHandler: authenticate }, async (request, reply) => {
    const data = updateProfileSchema.parse(request.body)

    const user = await User.findByIdAndUpdate(
      request.user.id,
      { ...data },
      { new: true }
    ).select('email name role avatar')

    if (!user) {
      return reply.status(404).send({ error: 'User not found' })
