import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'
import { StudyRoom } from '../models/StudyRoom.js'

const roomCreateSchema = z.object({
  name: z.string().min(1),
})

function generateRoomCode(): string {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789'
  let code = ''
  for (let i = 0; i < 6; i++) {
    code += chars[Math.floor(Math.random() * chars.length)]
  }
  return code
}

const roomRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Create room
  fastify.post('/create', { preHandler: authenticate }, async (request, reply) => {
    const { name } = roomCreateSchema.parse(request.body)

    let code = generateRoomCode()
    // Ensure unique
    while (await StudyRoom.findOne({ code })) {
      code = generateRoomCode()
    }

    const room = await StudyRoom.create({
      code,
      name,
      creatorId: request.user.id,
      expiresAt: new Date(Date.now() + 4 * 60 * 60 * 1000), // 4 hours
    })

    await room.populate('creatorId', 'id name')

    return reply.status(201).send(room)
  })

  // Get room by code
  fastify.get('/:code', async (request, reply) => {
    const { code } = request.params as { code: string }

    const room = await StudyRoom.findOne({ code: code.toUpperCase() }).populate('creatorId', 'id name')

    if (!room) {
      return reply.status(404).send({ error: 'Room not found' })
    }

    if (!room.isActive) {
      return reply.status(410).send({ error: 'Room is closed' })
    }

    return reply.send(room)
  })

  // Join room
  fastify.post('/:code/join', { preHandler: authenticate }, async (request, reply) => {
    const { code } = request.params as { code: string }

    const room = await StudyRoom.findOne({ code: code.toUpperCase() })

    if (!room) {
      return reply.status(404).send({ error: 'Room not found' })
    }

    if (!room.isActive) {
      return reply.status(410).send({ error: 'Room is closed' })
    }

    return reply.send({ message: 'Joined successfully', roomCode: room.code })
  })

  // Close room
  fastify.delete('/:code', { preHandler: authenticate }, async (request, reply) => {
    const { code } = request.params as { code: string }

    const room = await StudyRoom.findOne({ code: code.toUpperCase() })

    if (!room) {
      return reply.status(404).send({ error: 'Room not found' })
    }

    if (room.creatorId.toString() !== request.user.id && request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Only room creator can close' })
    }

    room.isActive = false
    await room.save()

    return reply.send({ message: 'Room closed' })
  })
}

export default roomRoutes

import Fastify from 'fastify'
import cors from '@fastify/cors'
import jwt from '@fastify/jwt'
import multipart from '@fastify/multipart'
import rateLimit from '@fastify/rate-limit'
import { config } from './config/index.js'
import mongodbPlugin from './plugins/mongodb.js'
import authRoutes from './routes/auth.js'
import articleRoutes from './routes/articles.js'
import commentRoutes from './routes/comments.js'
import newsletterRoutes from './routes/newsletter.js'
import roomRoutes from './routes/rooms.js'
import uploadRoutes from './routes/upload.js'
import userRoutes from './routes/users.js'

export async function buildApp() {
  const app = Fastify({
    logger: {
      level: config.NODE_ENV === 'production' ? 'warn' : 'info',
    },
  })

  // Plugins
  await app.register(cors, {
    origin: config.FRONTEND_URL,
    credentials: true,
  })

  await app.register(jwt, {
    secret: config.JWT_SECRET,
    sign: { expiresIn: '15m' },
  })

  await app.register(multipart, {
    limits: { fileSize: 500 * 1024 * 1024 }, // 500MB
  })

  await app.register(rateLimit, {
    max: 100,
    timeWindow: '1 minute',
  })

  // MongoDB
  await app.register(mongodbPlugin)

  // Health check
  app.get('/health', async () => ({ status: 'ok', timestamp: new Date().toISOString() }))

  // Global error handler
  app.setErrorHandler((err, request, reply) => {
    if ((err as any).name === 'ZodError') {
      return reply.status(400).send({ error: 'Validation failed', details: (err as any).issues })
    }
    if (err.validation) {
      return reply.status(400).send({ error: 'Validation failed', details: err.validation })
    }
    request.log.error(err)
    return reply.status(err.statusCode ?? 500).send({ error: err.message ?? 'Internal Server Error' })
  })

  // Routes
  await app.register(authRoutes, { prefix: '/api/auth' })
  await app.register(articleRoutes, { prefix: '/api/articles' })
  await app.register(commentRoutes, { prefix: '/api' })
  await app.register(newsletterRoutes, { prefix: '/api/newsletter' })
  await app.register(roomRoutes, { prefix: '/api/rooms' })
  await app.register(uploadRoutes, { prefix: '/api/upload' })
  await app.register(userRoutes, { prefix: '/api/users' })

  return app
}

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { authenticate } from '../middleware/auth.js'
import { v2 as cloudinary } from 'cloudinary'
import { config } from '../config/index.js'

cloudinary.config({
  cloud_name: config.CLOUDINARY_CLOUD_NAME,
  api_key: config.CLOUDINARY_API_KEY,
  api_secret: config.CLOUDINARY_API_SECRET,
})

const uploadRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Upload image
  fastify.post('/image', { preHandler: authenticate }, async (request, reply) => {
    const data = await request.file()

    if (!data) {
      return reply.status(400).send({ error: 'No file uploaded' })
    }

    const buffer = await data.toBuffer()

    const result = await new Promise<any>((resolve, reject) => {
      cloudinary.uploader.upload_stream(
        {
          folder: 'maiy-tech-hub/images',
          resource_type: 'image',
        },
        (error, result) => {
          if (error) reject(error)
          else resolve(result)
        }
      ).end(buffer)
    })

    return reply.send({
      url: result.secure_url,
      publicId: result.public_id,
      width: result.width,
      height: result.height,
    })
  })

  // Upload video
  fastify.post('/video', { preHandler: authenticate }, async (request, reply) => {
    const data = await request.file()

    if (!data) {
      return reply.status(400).send({ error: 'No file uploaded' })
    }

    // Max 500MB
    const buffer = await data.toBuffer()
    if (buffer.length > 500 * 1024 * 1024) {
      return reply.status(400).send({ error: 'File too large (max 500MB)' })
    }

    const result = await new Promise<any>((resolve, reject) => {
      cloudinary.uploader.upload_stream(
        {
          folder: 'maiy-tech-hub/videos',
          resource_type: 'video',
        },
        (error, result) => {
          if (error) reject(error)
          else resolve(result)
        }
      ).end(buffer)
    })

    return reply.send({
      url: result.secure_url,
      publicId: result.public_id,
      duration: result.duration,
    })
  })
}

export default uploadRoutes

import { FastifyRequest, FastifyReply } from 'fastify'

export async function authenticate(
  request: FastifyRequest,
  reply: FastifyReply
) {
  try {
    await request.jwtVerify()
  } catch (err) {
    reply.status(401).send({ error: 'Unauthorized' })
  }
}

export async function optionalAuth(
  request: FastifyRequest,
  reply: FastifyReply
) {
  try {
    await request.jwtVerify()
  } catch {
    // Ignore - allow anonymous access
  }
}

