  app.get('/health', async () => ({
    status: 'ok',
    timestamp: new Date().toISOString(),
  }))

  app.setErrorHandler((err, request, reply) => {
    if ((err as any).name === 'ZodError') {
      return reply.status(400).send({ error: 'Validation failed', details: (err as any).issues })
    }
    if (err.validation) {
      return reply.status(400).send({ error: 'Validation failed', details: err.validation })
    }
    request.log.error(err)
    return reply.status(err.statusCode ?? 500).send({ error: err.message ?? 'Internal Server Error' })
  })

  await app.register(authRoutes, { prefix: '/api/auth' })
  await app.register(articleRoutes, { prefix: '/api/articles' })
  await app.register(commentRoutes, { prefix: '/api' })
  await app.register(newsletterRoutes, { prefix: '/api/newsletter' })
  await app.register(roomRoutes, { prefix: '/api/rooms' })
  await app.register(uploadRoutes, { prefix: '/api/upload' })
  await app.register(userRoutes, { prefix: '/api/users' })

  return app
}

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import bcrypt from 'bcryptjs'
import { z } from 'zod'

const registerSchema = z.object({
  email: z.string().email(),
  password: z.string().min(8),
  name: z.string().min(2),
})

const loginSchema = z.object({
  email: z.string().email(),
  password: z.string(),
})

const authRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Register
  fastify.post('/register', async (request, reply) => {
    const body = registerSchema.parse(request.body)

    const existing = await fastify.prisma.user.findUnique({
      where: { email: body.email.toLowerCase() },
    })

    if (existing) {
      return reply.status(400).send({ error: 'Email already registered' })
    }

    const passwordHash = await bcrypt.hash(body.password, 12)

    const user = await fastify.prisma.user.create({
      data: {
        email: body.email.toLowerCase(),
        passwordHash,
        name: body.name,
      },
    })

    const accessToken = fastify.jwt.sign({
      id: user.id,
      email: user.email,
      role: user.role,
    })

    const refreshToken = fastify.jwt.sign(
      { id: user.id, email: user.email, role: user.role },
      { expiresIn: '7d' }
    )

    const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000)

    await fastify.prisma.refreshToken.create({
      data: { token: refreshToken, userId: user.id, expiresAt },
    })

    return reply.send({
      user: { id: user.id, email: user.email, name: user.name, role: user.role },
      accessToken,
      refreshToken,
    })
  })

  // Login
  fastify.post('/login', async (request, reply) => {
    const body = loginSchema.parse(request.body)

    const user = await fastify.prisma.user.findUnique({
      where: { email: body.email.toLowerCase() },
    })

    if (!user) {
      return reply.status(401).send({ error: 'Invalid credentials' })
    }

    const valid = await bcrypt.compare(body.password, user.passwordHash)
    if (!valid) {
      return reply.status(401).send({ error: 'Invalid credentials' })
    }

    const accessToken = fastify.jwt.sign({
      id: user.id,
      email: user.email,
      role: user.role,
    })

    const refreshToken = fastify.jwt.sign(
      { id: user.id, email: user.email, role: user.role },
      { expiresIn: '7d' }
    )

    // Token rotation: delete old tokens before creating new one
    await fastify.prisma.refreshToken.deleteMany({ where: { userId: user.id } })

    const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000)

    await fastify.prisma.refreshToken.create({
      data: { token: refreshToken, userId: user.id, expiresAt },
    })

    return reply.send({
      user: { id: user.id, email: user.email, name: user.name, role: user.role },
      accessToken,
      refreshToken,
    })
  })

  // Refresh token
  fastify.post('/refresh', async (request, reply) => {
    const { refreshToken } = request.body as { refreshToken: string }

    try {
      const decoded = fastify.jwt.verify(refreshToken) as { id: string; email: string; role: string }

      const stored = await fastify.prisma.refreshToken.findFirst({
        where: { token: refreshToken, expiresAt: { gt: new Date() } },
      })

      if (!stored) {
        return reply.status(401).send({ error: 'Invalid refresh token' })
      }

      const accessToken = fastify.jwt.sign({
        id: decoded.id,
        email: decoded.email,
        role: decoded.role,
      })

      return reply.send({ accessToken })
    } catch {
      return reply.status(401).send({ error: 'Invalid refresh token' })
    }
  })

  // Logout
  fastify.post('/logout', async (request, reply) => {
    const { refreshToken } = request.body as { refreshToken: string }

    if (refreshToken) {
      await fastify.prisma.refreshToken.deleteMany({ where: { token: refreshToken } })
    }

    return reply.send({ message: 'Logged out successfully' })
  })
}

export default authRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate } from '../middleware/auth.js'

const articleCreateSchema = z.object({
  slug: z.string().min(1),
  title: z.string().min(1),
  excerpt: z.string(),
  content: z.string(),
  category: z.enum(['AI', 'CTDL', 'WEB_DEV', 'DEVOPS', 'MOBILE']),
  tags: z.array(z.string()),
  coverImage: z.string().optional(),
  readingTime: z.number().optional(),
})

const articleUpdateSchema = articleCreateSchema.partial()

const articleQuerySchema = z.object({
  page: z.coerce.number().min(1).default(1),
  limit: z.coerce.number().min(1).max(100).default(10),
  category: z.string().optional(),
  tag: z.string().optional(),
  search: z.string().optional(),
})

const articleRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // List articles (public)
  fastify.get('/', async (request, reply) => {
    const query = articleQuerySchema.parse(request.query)
    const skip = (query.page - 1) * query.limit

    const where: any = { published: true }
    if (query.category) where.category = query.category.toUpperCase()
    if (query.tag) where.tags = { has: query.tag }
    if (query.search) {
      where.OR = [
        { title: { contains: query.search, mode: 'insensitive' } },
        { excerpt: { contains: query.search, mode: 'insensitive' } },
      ]
    }

    const [articles, total] = await Promise.all([
      fastify.prisma.article.findMany({
        where,
        skip,
        take: query.limit,
        orderBy: { publishedAt: 'desc' },
        include: {
          author: { select: { id: true, name: true, avatar: true } },
          _count: { select: { comments: true } },
        },
      }),
      fastify.prisma.article.count({ where }),
    ])

    return reply.send({
      articles,
      pagination: {
        page: query.page,
        limit: query.limit,
        total,
        totalPages: Math.ceil(total / query.limit),
      },
    })
  })

  // Get single article by slug
  fastify.get('/:slug', async (request, reply) => {
    const { slug } = request.params as { slug: string }

    const article = await fastify.prisma.article.findUnique({
      where: { slug },
      include: {
        author: { select: { id: true, name: true, avatar: true } },
        comments: {
          where: { parentId: null },
          orderBy: { createdAt: 'desc' },
          include: {
            author: { select: { id: true, name: true, avatar: true } },
            replies: {
              orderBy: { createdAt: 'asc' },
              include: {
                author: { select: { id: true, name: true, avatar: true } },
              },
            },
          },
        },
      },
    })

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    return reply.send(article)
  })

  // Create article (admin only)
  fastify.post('/', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const data = articleCreateSchema.parse(request.body)

    const article = await fastify.prisma.article.create({
      data: { ...data, authorId: request.user.id },
      include: { author: { select: { id: true, name: true, avatar: true } } },
    })

    return reply.status(201).send(article)
  })

  // Update article (admin only)
  fastify.put('/:id', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }
    const data = articleUpdateSchema.parse(request.body)

    const article = await fastify.prisma.article.update({
      where: { id },
      data,
      include: { author: { select: { id: true, name: true, avatar: true } } },
    })

    return reply.send(article)
  })

  // Delete article (admin only)
  fastify.delete('/:id', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }

    await fastify.prisma.article.delete({ where: { id } })
    return reply.send({ message: 'Article deleted' })
  })

  // Publish/unpublish article (admin only)
  fastify.patch('/:id/publish', { preHandler: authenticate }, async (request, reply) => {
    if (request.user.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Admin only' })
    }

    const { id } = request.params as { id: string }
    const { published } = request.body as { published: boolean }

    const article = await fastify.prisma.article.update({
      where: { id },
      data: { published, publishedAt: published ? new Date() : null },
    })

    return reply.send(article)
  })
}

export default articleRoutes

import { FastifyInstance, FastifyPluginAsync } from 'fastify'
import { z } from 'zod'
import { authenticate, optionalAuth } from '../middleware/auth.js'

const commentSchema = z.object({
  content: z.string().min(1),
  authorName: z.string().min(1).optional(),
  parentId: z.string().optional(),
})

const commentRoutes: FastifyPluginAsync = async (fastify: FastifyInstance) => {
  // Get comments for article
  fastify.get('/articles/:slug/comments', async (request, reply) => {
    const { slug } = request.params as { slug: string }

    const article = await fastify.prisma.article.findUnique({ where: { slug }, select: { id: true } })

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    const comments = await fastify.prisma.comment.findMany({
      where: { articleId: article.id, parentId: null },
      orderBy: { createdAt: 'desc' },
      include: {
        author: { select: { id: true, name: true, avatar: true } },
        replies: {
          orderBy: { createdAt: 'asc' },
          include: {
            author: { select: { id: true, name: true, avatar: true } },
          },
        },
      },
    })

    return reply.send(comments)
  })

  // Add comment
  fastify.post('/articles/:slug/comments', { preHandler: optionalAuth }, async (request, reply) => {
    const { slug } = request.params as { slug: string }
    const data = commentSchema.parse(request.body)

    const article = await fastify.prisma.article.findUnique({ where: { slug }, select: { id: true } })

    if (!article) {
      return reply.status(404).send({ error: 'Article not found' })
    }

    let authorName = 'Anonymous'
    let authorId: string | null = null

    if (request.user?.id) {
      const user = await fastify.prisma.user.findUnique({
        where: { id: request.user.id },
        select: { name: true },
      })
      authorName = user?.name ?? 'User'
      authorId = request.user.id
    } else {
      authorName = data.authorName ?? 'Anonymous'
    }

    const comment = await fastify.prisma.comment.create({
      data: {
        articleId: article.id,
        authorId,
        authorName,
        content: data.content,
        parentId: data.parentId ?? null,
      },
      include: { author: { select: { id: true, name: true, avatar: true } } },
    })

    return reply.status(201).send(comment)
  })

  // Delete comment
  fastify.delete('/comments/:id', { preHandler: optionalAuth }, async (request, reply) => {
    const { id } = request.params as { id: string }

    const comment = await fastify.prisma.comment.findUnique({ where: { id } })

    if (!comment) {
      return reply.status(404).send({ error: 'Comment not found' })
    }

    if (comment.authorId !== request.user?.id && request.user?.role !== 'ADMIN') {
      return reply.status(403).send({ error: 'Forbidden' })
    }

    await fastify.prisma.comment.delete({ where: { id } })
    return reply.send({ message: 'Comment deleted' })
  })
}

