  })
}

async function createRegularUser(prisma: any) {
  const hash = await bcrypt.hash('UserPass123!', 12)
  return prisma.user.create({
    data: { email: uniqueEmail(), passwordHash: hash, name: 'Regular User', role: Role.USER },
  })
}

function signToken(app: FastifyInstance, payload: { id: string; email: string; role: string }) {
  return app.jwt.sign(payload)
}

