import { describe, it, expect, beforeAll, afterAll } from 'vitest'
import Fastify, { FastifyInstance } from 'fastify'
import jwt from '@fastify/jwt'
import authRoutes from '../src/routes/auth.js'
import { getPrisma, connectPrisma, uniqueEmail } from './setup.js'

describe('Auth Routes', () => {
  let app: FastifyInstance

  beforeAll(async () => {
    await connectPrisma()
    app = Fastify()
    await app.register(jwt, { secret: 'test-jwt-secret-for-auth-tests', sign: { expiresIn: '15m' } })
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ;(app as any).prisma = getPrisma()
    await app.register(authRoutes, { prefix: '/api/auth' })
    await app.ready()
  })

  afterAll(async () => {
    await app.close()
  })

  describe('POST /api/auth/register', () => {
    it('registers a new user successfully', async () => {
      const email = uniqueEmail()
      const res = await app.inject({
        method: 'POST',
        url: '/api/auth/register',
        payload: { email, password: 'SecurePass123!', name: 'New User' },
      })
      expect(res.statusCode).toBe(200)
      const body = JSON.parse(res.body)
      expect(body.user.email).toBe(email)
      expect(body.user.name).toBe('New User')
      expect(body.user.role).toBe('USER')
      expect(body.accessToken).toBeDefined()
      expect(body.refreshToken).toBeDefined()
    })

    it('returns 400 for duplicate email', async () => {
      const email = uniqueEmail()
      await app.inject({
        method: 'POST',
        url: '/api/auth/register',
        payload: { email, password: 'SecurePass123!', name: 'First' },
      })
      const res = await app.inject({
        method: 'POST',
        url: '/api/auth/register',
        payload: { email, password: 'SecurePass123!', name: 'Second' },
      })
      expect(res.statusCode).toBe(400)
      expect(JSON.parse(res.body).error).toBe('Email already registered')
    })

    it('returns 400 for invalid email format', async () => {
      const res = await app.inject({
        method: 'POST',
        url: '/api/auth/register',
        payload: { email: 'not-an-email', password: 'SecurePass123!', name: 'Test' },
      })
      expect(res.statusCode).toBe(400)
    })

    it('returns 400 for password < 8 chars', async () => {
      const res = await app.inject({
        method: 'POST',
        url: '/api/auth/register',
        payload: { email: uniqueEmail(), password: 'short', name: 'Test' },
      })
      expect(res.statusCode).toBe(400)
    })

    it('returns 400 for missing fields', async () => {
      const res = await app.inject({
        method: 'POST',
        url: '/api/auth/register',
        payload: { email: uniqueEmail() },
      })
      expect(res.statusCode).toBe(400)
    })
  })

  describe('POST /api/auth/login', () => {
    it('logs in with valid credentials', async () => {
      const email = uniqueEmail()
      await app.inject({
        method: 'POST',
        url: '/api/auth/register',
        payload: { email, password: 'SecurePass123!', name: 'Login User' },
      })
      const res = await app.inject({
        method: 'POST',
        url: '/api/auth/login',
        payload: { email, password: 'SecurePass123!' },
      })
      expect(res.statusCode).toBe(200)
      const body = JSON.parse(res.body)
      expect(body.user.email).toBe(email)
      expect(body.accessToken).toBeDefined()
      expect(body.refreshToken).toBeDefined()
    })

    it('returns 401 for wrong password', async () => {
      const email = uniqueEmail()
      await app.inject({
        method: 'POST',
        url: '/api/auth/register',
        payload: { email, password: 'SecurePass123!', name: 'Wrong Pass' },
      })
      const res = await app.inject({
        method: 'POST',
        url: '/api/auth/login',
        payload: { email, password: 'WrongPassword1!' },
      })
      expect(res.statusCode).toBe(401)
      expect(JSON.parse(res.body).error).toBe('Invalid credentials')
    })

    it('returns 401 for non-existent email', async () => {
      const res = await app.inject({
        method: 'POST',
        url: '/api/auth/login',
        payload: { email: uniqueEmail(), password: 'SecurePass123!' },
      })
      expect(res.statusCode).toBe(401)
      expect(JSON.parse(res.body).error).toBe('Invalid credentials')
    })
  })

  describe('POST /api/auth/refresh', () => {
    it('refreshes token with valid refresh token', async () => {
      const email = uniqueEmail()
