import { describe, it, expect, beforeAll, afterAll, beforeEach, afterEach } from 'vitest'
import Fastify, { FastifyInstance } from 'fastify'
import jwt from '@fastify/jwt'
import articleRoutes from '../src/routes/articles.js'
import { getPrisma, connectPrisma, createAdminUser, createRegularUser } from './setup.js'

function signToken(app: FastifyInstance, payload: { id: string; email: string; role: string }) {
  return app.jwt.sign(payload)
}

describe('Article Routes', () => {
  let app: FastifyInstance
  let adminToken: string
  let userToken: string

  beforeAll(async () => {
    await connectPrisma()
    app = Fastify()
    await app.register(jwt, { secret: 'test-jwt-secret-for-articles', sign: { expiresIn: '15m' } })
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    ;(app as any).prisma = getPrisma()
    await app.register(articleRoutes, { prefix: '/api/articles' })
    await app.ready()
  })

  afterAll(async () => {
    await app.close()
  })

  beforeEach(async () => {
    const admin = await createAdminUser()
    const user = await createRegularUser()
    adminToken = signToken(app, { id: admin.id, email: admin.email, role: 'ADMIN' })
    userToken = signToken(app, { id: user.id, email: user.email, role: 'USER' })
  })

  afterEach(async () => {
    const p = getPrisma()
    await p.comment.deleteMany()
    await p.article.deleteMany()
    await p.refreshToken.deleteMany()
    await p.newsletter.deleteMany()
    await p.studyRoom.deleteMany()
    await p.user.deleteMany()
  })

  describe('GET /api/articles', () => {
    it('returns empty list when no articles', async () => {
      const res = await app.inject({ method: 'GET', url: '/api/articles' })
      expect(res.statusCode).toBe(200)
      const body = JSON.parse(res.body)
      expect(body.articles).toEqual([])
      expect(body.pagination.total).toBe(0)
    })

    it('returns published articles', async () => {
      const admin = await getPrisma().user.findFirst({ where: { role: 'ADMIN' } })!
      await getPrisma().article.create({
        data: {
          slug: 'test-article-1',
          title: 'Test Article',
          excerpt: 'Excerpt',
          content: 'Content',
          category: 'AI',
          tags: ['test'],
          authorId: admin.id,
          published: true,
          publishedAt: new Date(),
        },
      })
      const res = await app.inject({ method: 'GET', url: '/api/articles' })
      const body = JSON.parse(res.body)
      expect(body.articles.length).toBe(1)
      expect(body.articles[0].slug).toBe('test-article-1')
    })

    it('hides unpublished articles from public', async () => {
      const admin = await getPrisma().user.findFirst({ where: { role: 'ADMIN' } })!
      await getPrisma().article.create({
        data: {
          slug: 'unpublished-article',
          title: 'Unpublished',
          excerpt: 'x',
          content: 'x',
          category: 'WEB_DEV',
          tags: [],
          authorId: admin.id,
          published: false,
        },
      })
      const res = await app.inject({ method: 'GET', url: '/api/articles' })
      const body = JSON.parse(res.body)
      expect(body.articles.some((a: any) => a.slug === 'unpublished-article')).toBe(false)
    })

    it('filters by category', async () => {
      const admin = await getPrisma().user.findFirst({ where: { role: 'ADMIN' } })!
      await getPrisma().article.create({
        data: {
          slug: 'category-test',
          title: 'Category Test',
          excerpt: 'x',
          content: 'x',
          category: 'DEVOPS',
          tags: [],
          authorId: admin.id,
          published: true,
          publishedAt: new Date(),
        },
      })
      const res = await app.inject({ method: 'GET', url: '/api/articles?category=DEVOPS' })
      const body = JSON.parse(res.body)
      expect(body.articles.every((a: any) => a.category === 'DEVOPS')).toBe(true)
    })

    it('filters by tag', async () => {
      const res = await app.inject({ method: 'GET', url: '/api/articles?tag=test' })
      const body = JSON.parse(res.body)
      expect(body.articles.every((a: any) => a.tags.includes('test'))).toBe(true)
    })

    it('paginates results', async () => {
      const res = await app.inject({ method: 'GET', url: '/api/articles?page=1&limit=1' })
      const body = JSON.parse(res.body)
      expect(body.articles.length).toBe(1)
      expect(body.pagination.page).toBe(1)
      expect(body.pagination.limit).toBe(1)
    })

    it('returns 400 for limit > 100', async () => {
      const res = await app.inject({ method: 'GET', url: '/api/articles?limit=200' })
      expect(res.statusCode).toBe(400)
    })
  })

  describe('GET /api/articles/:slug', () => {
    it('returns article by slug', async () => {
      const admin = await getPrisma().user.findFirst({ where: { role: 'ADMIN' } })!
      await getPrisma().article.create({
        data: {
          slug: 'test-article-1',
          title: 'Test Article',
          excerpt: 'x',
          content: 'x',
          category: 'AI',
          tags: [],
          authorId: admin.id,
          published: true,
          publishedAt: new Date(),
        },
      })
      const res = await app.inject({ method: 'GET', url: '/api/articles/test-article-1' })
      expect(res.statusCode).toBe(200)
      expect(JSON.parse(res.body).slug).toBe('test-article-1')
    })

    it('returns 404 for non-existent slug', async () => {
      const res = await app.inject({ method: 'GET', url: '/api/articles/non-existent-slug' })
      expect(res.statusCode).toBe(404)
    })
  })

  describe('POST /api/articles', () => {
    it('creates article as admin', async () => {
      const res = await app.inject({
        method: 'POST',
        url: '/api/articles/',
        headers: { authorization: `Bearer ${adminToken}` },
        payload: {
          slug: 'new-admin-article',
          title: 'New Article',
          excerpt: 'A great article',
          content: 'Full content here',
          category: 'CTDL',
          tags: ['algorithms'],
        },
      })
      expect(res.statusCode).toBe(201)
      const body = JSON.parse(res.body)
      expect(body.slug).toBe('new-admin-article')
      expect(body.author.id).toBeDefined()
    })

    it('returns 403 for non-admin', async () => {
      const res = await app.inject({
        method: 'POST',
        url: '/api/articles/',
        headers: { authorization: `Bearer ${userToken}` },
        payload: {
          slug: 'user-article',
          title: 'User Article',
          excerpt: 'x',
          content: 'x',
          category: 'WEB_DEV',
          tags: [],
        },
      })
      expect(res.statusCode).toBe(403)
    })

    it('returns 401 without auth', async () => {
      const res = await app.inject({
        method: 'POST',
        url: '/api/articles/',
        payload: { slug: 'x', title: 'x', excerpt: 'x', content: 'x', category: 'AI', tags: [] },
      })
      expect(res.statusCode).toBe(401)
    })
  })

  describe('PUT /api/articles/:id', () => {
    it('updates article as admin', async () => {
      const admin = await getPrisma().user.findFirst({ where: { role: 'ADMIN' } })!
      const article = await getPrisma().article.create({
        data: {
          slug: 'update-test-article',
          title: 'Original Title',
          excerpt: 'x',
          content: 'x',
          category: 'MOBILE',
          tags: [],
          authorId: admin.id,
          published: false,
        },
      })
      const res = await app.inject({
        method: 'PUT',
        url: `/api/articles/${article.id}`,
        headers: { authorization: `Bearer ${adminToken}` },
        payload: {
          slug: 'update-test-article',
          title: 'Updated Title',
          excerpt: 'x',
          content: 'x',
          category: 'MOBILE',
          tags: [],
        },
      })
      expect(res.statusCode).toBe(200)
      expect(JSON.parse(res.body).title).toBe('Updated Title')
    })
  })

  describe('DELETE /api/articles/:id', () => {
    it('deletes article as admin', async () => {
      const admin = await getPrisma().user.findFirst({ where: { role: 'ADMIN' } })!
      const article = await getPrisma().article.create({
        data: {
          slug: 'delete-test-article',
          title: 'To Delete',
          excerpt: 'x',
          content: 'x',
          category: 'AI',
          tags: [],
          authorId: admin.id,
          published: false,
        },
      })
      const res = await app.inject({
        method: 'DELETE',
        url: `/api/articles/${article.id}`,
        headers: { authorization: `Bearer ${adminToken}` },
      })
      expect(res.statusCode).toBe(200)
    })
  })

  describe('PATCH /api/articles/:id/publish', () => {
    it('publishes article as admin', async () => {
      const admin = await getPrisma().user.findFirst({ where: { role: 'ADMIN' } })!
      const article = await getPrisma().article.create({
        data: {
          slug: 'publish-test-article',
          title: 'Publish Me',
          excerpt: 'x',
          content: 'x',
          category: 'AI',
          tags: [],
          authorId: admin.id,
          published: false,
        },
      })
      const res = await app.inject({
        method: 'PATCH',
        url: `/api/articles/${article.id}/publish`,
        headers: { authorization: `Bearer ${adminToken}` },
        payload: { published: true },
      })
      expect(res.statusCode).toBe(200)
      expect(JSON.parse(res.body).published).toBe(true)
    })
  })
})

